def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    popen_kwargs = self._get_priority_popen_kwargs()

    try:
        try:
            c = subprocess.Popen(
                f'{editor} "{filename}"', env=environ, shell=True, **popen_kwargs
            )
        except OSError:
            # The priority-related kwargs may not be supported on this
            # platform/environment. Fall back to launching without them
            # rather than failing the whole edit operation.
            if not popen_kwargs:
                raise
            c = subprocess.Popen(f'{editor} "{filename}"', env=environ, shell=True)

        exit_code = c.wait()
        if exit_code != 0:
            raise ClickException(
                _("{editor}: Editing failed").format(editor=editor)
            )
    except OSError as e:
        raise ClickException(
            _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
        ) from e

def _get_priority_popen_kwargs(self) -> dict[str, t.Any]:
    """Build the extra ``subprocess.Popen`` kwargs needed to launch the
    editor with ``self.process_priority``, if set. Returns an empty
    dict if no priority was requested or it can't be applied on this
    platform.
    """
    if self.process_priority is None:
        return {}

    if WIN:
        import subprocess

        priority_classes = {
            "low": subprocess.IDLE_PRIORITY_CLASS,
            "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,
            "normal": subprocess.NORMAL_PRIORITY_CLASS,
            "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,
            "high": subprocess.HIGH_PRIORITY_CLASS,
        }
        return {"creationflags": priority_classes[self.process_priority]}

    nice_values = {
        "low": 19,
        "below_normal": 10,
        "normal": 0,
        "above_normal": -5,
        "high": -10,
    }
    nice_value = nice_values[self.process_priority]

    def _set_priority() -> None:
        try:
            os.nice(nice_value)
        except OSError:
            # e.g. lacking permission to raise priority. The editor
            # should still launch with the default priority.
            pass

    return {"preexec_fn": _set_priority}

